INSERT INTO public.projects (title, description, problem, solution, tech_stack, category, featured, display_order) VALUES
('Smart Outlet IoT System', 'An IoT Smart Outlet with real-time energy monitoring via ACS712 sensors and a cloud dashboard.', 'Homeowners have zero visibility into which appliances consume the most energy, and no way to control outlets remotely or detect safety hazards in real time.', 'Built an IoT Smart Outlet with real-time energy monitoring via ACS712 sensors, a cloud dashboard for remote control, and an AI chatbot interface for natural-language commands.', ARRAY['Arduino/ESP32', 'ACS712', 'MQTT', 'Cloud Dashboard', 'AI Chatbot'], 'iot', true, 1),
('Automated Cacao Processor', 'An automated system that controls wash cycles, monitors mass, and handles discharge automatically.', 'Small-scale cacao farmers rely on manual post-harvest processing — inconsistent wash timing, no way to measure mass accurately, and labor-intensive discharge.', 'Engineered an automated system using Arduino, load cells, and servo motors that controls wash cycles by time, monitors mass in real-time, and handles discharge automatically.', ARRAY['Arduino', 'C++', 'Load Cells', 'Servo Motors', 'Safety Logic'], 'embedded', true, 2),
('Preventive Maintenance System', 'A centralized AppSheet platform that tracks vehicle data and automates service reminders.', 'Businesses track vehicle maintenance using spreadsheets and memory — leading to missed service schedules, unexpected breakdowns, and costly downtime.', 'Developed a centralized AppSheet platform that tracks vehicle data, automates service reminders, and logs complete maintenance history in one dashboard.', ARRAY['AppSheet', 'Google Sheets', 'Automation Workflows'], 'automation', true, 3),
('iSRC 2026 Research', 'Presented peer-reviewed research at the International Students Research Congress 2026.', NULL, NULL, ARRAY['Research', 'Embedded Systems'], 'research', false, 4),
('ACS712 Driver Library', 'A lightweight, optimized driver library for the ACS712 Hall effect current sensor. Published on GitHub.', NULL, NULL, ARRAY['C++', 'Arduino', 'PIC'], 'open-source', false, 5),
('SCT013-100 Driver Library', 'A lightweight driver for SCT013-100 Non-Invasive Current Transformers. Designed for IoT energy monitoring on Arduino and ESP32. Includes noise filtering and calibration helpers.', NULL, NULL, ARRAY['C++', 'Arduino', 'ESP32'], 'open-source', false, 6);
